[Tue 2026-04-07 09:17 UTC] [Subagent Context] You are running as a subagent (depth 1/1). Results auto-announce to your requester; do not busy-poll for status.

[Subagent Task]: Add rate limiting and cost tracking to MAGI v2 backend.

Edit ~/magi-v2/backend/server.js

## 1. Rate Limiting
Add per-user rate limiting for API calls:

- Free users (role: 'user'): 50 messages/day, 3 deep thinks/day
- Admin users (role: 'admin'): unlimited

Implementation: in-memory Map tracking calls per user per day. Reset at midnight UTC.

Add this BEFORE the existing route handlers:

```javascript
// Rate limiting
const rateLimits = new Map(); // userId -> {messages: count, deepThinks: count, date: 'YYYY-MM-DD'}

function checkRateLimit(username, type = 'message') {
  const today = new Date().toISOString().split('T')[0];
  const auth = loadAuth();
  const user = auth.users[username];
  if (!user) return { allowed: false, reason: 'Unknown user' };
  if (user.role === 'admin') return { allowed: true };

  let limits = rateLimits.get(username);
  if (!limits || limits.date !== today) {
    limits = { messages: 0, deepThinks: 0, date: today };
    rateLimits.set(username, limits);
  }

  if (type === 'message' && limits.messages >= 50) {
    return { allowed: false, reason: 'Daily message limit (50) reached' };
  }
  if (type === 'deepThink' && limits.deepThinks >= 3) {
    return { allowed: false, reason: 'Daily Deep Think limit (3) reached' };
  }

  limits[type === 'deepThink' ? 'deepThinks' : 'messages']++;
  return { allowed: true, remaining: type === 'deepThink' ? 3 - limits.deepThinks : 50 - limits.messages };
}
```

Apply to:
- POST /api/chat → checkRateLimit(username, 'message')
- POST /api/deep-think → checkRateLimit(username, 'deepThink')

## 2. Cost Tracking
Track Bedrock token usage per user.

Add to the existing streamAI or callBedrockSimple function:

```javascript
// Cost tracking
const COST_FILE = join(__dirname, 'data', 'costs.json');

function trackCost(username, inputTokens, outputTokens, model) {
  let costs = {};
  try { costs = JSON.parse(readFileSync(COST_FILE, 'utf8')); } catch {}

  const today = new Date().toISOString().split('T')[0];
  if (!costs[today]) costs[today] = {};
  if (!costs[today][username]) costs[today][username] = { input: 0, output: 0, calls: 0 };

  costs[today][username].input += inputTokens;
  costs[today][username].output += outputTokens;
  costs[today][username].calls += 1;

  // Keep only last 30 days
  const keys = Object.keys(costs).sort();
  while (keys.length > 30) { delete costs[keys.shift()]; }

  writeFileSync(COST_FILE, JSON.stringify(costs, null, 2));
}
```

## 3. Add GET /api/costs endpoint
Returns cost data for admin users only.

Write changes directly to server.js. Don't break existing functionality.

import Fastify from 'fastify'
import websocket from '@fastify/websocket'
import fstatic from '@fastify/static'
import cors from '@fastify/cors'
import multipart from '@fastify/multipart'
import { BedrockRuntimeClient, InvokeModelWithResponseStreamCommand } from '@aws-sdk/client-bedrock-runtime'
import { fileURLToPath } from 'url'
import { dirname, join, resolve, normalize } from 'path'
import { readFileSync, writeFileSync, existsSync, mkdirSync, readdirSync, statSync, unlinkSync, renameSync, createReadStream, createWriteStream } from 'fs'
import { execSync, exec as execCb } from 'child_process'
import JSON5 from 'json5'
import { pipeline } from 'stream/promises'
import crypto from 'crypto'

const __dirname = dirname(fileURLToPath(import.meta.url))
const HOME = process.env.HOME || '/home/openclaw'
const PORT = process.env.PORT || 3002
const INTENSITY_FILE = join(__dirname, 'data', 'intensity.json')

// ── Agents ──────────────────────────────────────────────
const AGENTS = {
  // L1 · Intelligence
  metis:    { name: 'Metis',    color: '#00897B', layer: 'L1', layerName: 'Intelligence',    order: 1,  role: 'The Librarian',   desc: 'Research & fact-finding',              soul: 'You are Metis, a research analyst. Find facts, provide sources, be thorough.' },
  sophia:   { name: 'Sophia',   color: '#3F51B5', layer: 'L1', layerName: 'Intelligence',    order: 2,  role: 'The Scholar',     desc: 'Academic analysis & thesis',            soul: 'You are Sophia, an academic researcher. Deep analysis, cite references.' },
  rafael:   { name: 'Rafael',   color: '#34A853', layer: 'L2', layerName: 'Strategy',        order: 3,  role: 'The Architect',   desc: 'Strategy & big decisions',              soul: 'You are Rafael, a strategic architect. Focus on big-picture planning and coordination.' },
  azrael:   { name: 'Azrael',   color: '#CDDC39', layer: 'L3', layerName: 'Guard Rails',     order: 4,  role: 'The Auditor',     desc: 'Budget & cost analysis',                soul: 'You are Azrael, a financial analyst. Always quote figures in USD and IDR (rate 16000).' },
  remiel:   { name: 'Remiel',   color: '#607D8B', layer: 'L3', layerName: 'Guard Rails',     order: 5,  role: 'The Sentry',      desc: 'Legal & compliance (ID)',                soul: 'You are Remiel, a compliance officer. Cite Indonesian law with article numbers.' },
  samael:   { name: 'Samael',   color: '#E91E63', layer: 'L3', layerName: 'Guard Rails',     order: 6,  role: 'The Prosecutor',  desc: 'Challenge assumptions & find flaws',    soul: 'You are Samael, a critical thinker. Challenge assumptions, find contradictions.' },
  uriel:    { name: 'Uriel',    color: '#FF6D00', layer: 'L4', layerName: 'Blueprint',       order: 7,  role: 'The Validator',   desc: 'Tech validation & testing',             soul: 'You are Uriel, a technical validator. Focus on testing, verification, and quality.' },
  zadkiel:  { name: 'Zadkiel',  color: '#FF5722', layer: 'L4', layerName: 'Blueprint',       order: 8,  role: 'The Builder',     desc: 'UI/UX & product design',                soul: 'You are Zadkiel, a product designer. Focus on UX, mobile-first, quality.' },
  michael:  { name: 'Michael',  color: '#4285F4', layer: 'L5', layerName: 'Core Council',    order: 9,  role: 'Wise Advisor',    desc: 'Risk & reality checks',                 soul: 'You are Michael, a wise strategic advisor. Be concise, direct, and helpful. Give actionable advice.' },
  gabriel:  { name: 'Gabriel',  color: '#FBBC04', layer: 'L5', layerName: 'Core Council',    order: 10, role: 'The Voice',       desc: 'Copywriting & marketing',               soul: 'You are Gabriel, a communications expert. Focus on messaging, copywriting, and marketing.' },
  raguel:   { name: 'Raguel',   color: '#00BCD4', layer: 'L5', layerName: 'Core Council',    order: 11, role: 'The Friend',      desc: 'Outreach & recruitment',                soul: 'You are Raguel, a relationship builder. Focus on outreach, recruitment, and partnerships.' },
  sarael:   { name: 'Sarael',   color: '#9C27B0', layer: 'L3', layerName: 'Guard Rails',     order: 12, role: 'The Scribe',      desc: 'Summarize & synthesize debates',        soul: 'You are Sarael, a synthesizer. Summarize discussions, find patterns, end with one unanswered question.' },
}

// Layer display order
const LAYER_ORDER = ['L1', 'L2', 'L3', 'L4', 'L5']

// ── Intensity System ────────────────────────────────────
const PRESETS = {
  full:    { label: 'Full Power', desc: 'All agents at max depth',      base: 10 },
  focus:   { label: 'Focus',      desc: 'Only key agents respond fully', base: 3, overrides: { michael: 10, rafael: 10, uriel: 8 } },
  quiet:   { label: 'Quiet',      desc: 'Minimal output, quick answers', base: 2 },
  balanced:{ label: 'Balanced',   desc: 'Smart defaults per layer',      base: 5, overrides: { michael: 8, rafael: 8, samael: 7, sarael: 7, uriel: 7, zadkiel: 6 } },
}
const INTENSITY_MODIFIERS = {
  1:  'CRITICAL: Reply in ONE sentence only. No headings, no lists, no paragraphs. Maximum 30 words.',
  2:  'Reply in 2-3 sentences maximum. No headings. Keep it under 50 words.',
  3:  'Reply in one short paragraph. Key points only. Under 80 words.',
  4:  'Reply in 2-3 short paragraphs. Cover main points briefly.',
  5:  'Standard depth. Cover the topic with reasonable detail.',
  6:  'Go deeper. Provide analysis and supporting points.',
  7:  'Thorough response. Cover multiple angles with examples.',
  8:  'Detailed and comprehensive. Full analysis with evidence.',
  9:  'Very detailed. Exhaustive analysis, edge cases, nuances.',
  10: 'Maximum depth. Leave nothing unsaid. Full expert analysis with examples, edge cases, and recommendations.',
}

function loadIntensity() {
  try {
    if (existsSync(INTENSITY_FILE)) return JSON.parse(readFileSync(INTENSITY_FILE, 'utf8'))
  } catch {}
  // Default: all agents at 5
  const def = { preset: 'balanced', agents: {} }
  for (const id of Object.keys(AGENTS)) def.agents[id] = 5
  // Apply balanced overrides
  if (PRESETS.balanced.overrides) Object.assign(def.agents, PRESETS.balanced.overrides)
  return def
}
function saveIntensity(data) {
  try { writeFileSync(INTENSITY_FILE, JSON.stringify(data, null, 2)) } catch {}
}
let intensityState = loadIntensity()

function getIntensityPrompt(agentId) {
  const level = intensityState.agents[agentId] ?? 5
  return INTENSITY_MODIFIERS[level] || INTENSITY_MODIFIERS[5]
}

// ── Bedrock ─────────────────────────────────────────────
const bedrock = new BedrockRuntimeClient({ region: process.env.AWS_REGION || 'us-west-2' })
const DEFAULT_MODEL = 'us.anthropic.claude-sonnet-4-6'
const AVAILABLE_MODELS = {
  'us.anthropic.claude-opus-4-6-v1':              { name: 'Claude Opus 4.6', tier: 'max', label: 'MAX' },
  'us.anthropic.claude-sonnet-4-6':               { name: 'Claude Sonnet 4.6', tier: 'standard', label: 'STD' },
  'us.anthropic.claude-sonnet-4-20250514-v1:0':   { name: 'Claude Sonnet 4.0', tier: 'standard', label: 'STD' },
  'us.anthropic.claude-3-5-haiku-20241022-v1:0':  { name: 'Claude Haiku 3.5', tier: 'eco', label: 'ECO' },
  'us.anthropic.claude-3-haiku-20240307-v1:0':    { name: 'Claude Haiku 3.0', tier: 'budget', label: 'BDG' },
}
const MODELS_FILE = join(__dirname, 'data', 'models.json')
function loadModels() {
  try { return JSON.parse(readFileSync(MODELS_FILE, 'utf8')) } catch { return {} }
}
function saveModels(data) {
  try { writeFileSync(MODELS_FILE, JSON.stringify(data, null, 2)) } catch {}
}
let modelOverrides = loadModels()

function getModelForAgent(agentId) {
  return modelOverrides[agentId] || DEFAULT_MODEL
}

// Shared memory — loaded once, injected into all agents
const SHARED_MEMORY_FILE = join(__dirname, 'data', 'shared-memory.json')
function loadSharedMemory() {
  try { if (existsSync(SHARED_MEMORY_FILE)) return JSON.parse(readFileSync(SHARED_MEMORY_FILE, 'utf8')) } catch {}
  return {}
}
function getSharedContext() {
  const mem = loadSharedMemory()
  return `
SHARED KNOWLEDGE (you are part of the MAGI system — know this context):
- Project: ${mem.project?.name || 'MAGI'} — ${mem.project?.description || ''}
- Owner: ${mem.users?.richard?.role || 'Admin'} Richard Chandra Tjiang
- Your fellow agents: ${mem.agents?.list || '12 agents'}
- Infrastructure: ${mem.infrastructure?.magi_v2 || ''}, ${mem.infrastructure?.caddy || ''}
- Available apps: Chat, Vault, Files, Analytics, Settings, Monitor, Dashboard
- V1 history: ${mem.costs?.v1_total || ''}, now on V2 with real-time tracking
- You CAN reference other agents by name and know their roles
- You ARE AWARE of the full system architecture and project history
`
}

// Global formatting instructions prepended to all agents
const FORMAT_PROMPT = `
CURRENT FACTS (as of March 2026):
- President of Indonesia: Prabowo Subianto (inaugurated Oct 20, 2024)
- Vice President of Indonesia: Gibran Rakabuming Raka
- President of the United States: Donald Trump (inaugurated Jan 20, 2025)
- Current year: 2026

FORMATTING RULES (always follow):
- Use **bold** for key terms and emphasis
- Use ## headings and ### subheadings to structure longer responses
- Use bullet points (- ) and numbered lists for clarity
- Use tables (| col | col |) when comparing data
- Use \`code\` for technical terms, commands, filenames
- Use > blockquotes for important callouts
- Use emoji naturally to make responses feel alive and engaging 🎯
- Break text into short paragraphs — never wall of text
- Start with a direct answer, then elaborate
- Be expressive, warm, and professional — not robotic
`

async function* streamBedrock(systemPrompt, userText, signal, agentId) {
  const modelId = agentId ? getModelForAgent(agentId) : DEFAULT_MODEL
  console.log(`[Bedrock] agent=${agentId} model=${modelId}`)
  const cmd = new InvokeModelWithResponseStreamCommand({
    modelId,
    contentType: 'application/json',
    accept: 'application/json',
    body: JSON.stringify({
      anthropic_version: 'bedrock-2023-05-31',
      max_tokens: 8192,
      system: systemPrompt,
      messages: [{ role: 'user', content: userText }]
    })
  })
  const resp = await bedrock.send(cmd, { abortSignal: signal })
  let inputTokens = 0, outputTokens = 0
  for await (const event of resp.body) {
    if (signal?.aborted) break
    if (event.chunk) {
      const json = JSON.parse(new TextDecoder().decode(event.chunk.bytes))
      if (json.type === 'content_block_delta' && json.delta?.text) {
        yield json.delta.text
      }
      if (json.type === 'message_delta' && json.usage) {
        outputTokens = json.usage.output_tokens || 0
      }
      if (json.type === 'message_start' && json.message?.usage) {
        inputTokens = json.message.usage.input_tokens || 0
      }
    }
  }
  // Track analytics
  try { trackUsage(agentId || 'unknown', modelId, inputTokens, outputTokens) } catch {}
}

// ── Ollama Provider ─────────────────────────────────────
const PROVIDER_FILE = join(__dirname, 'data', 'provider.json')
function loadProvider() { try { if (existsSync(PROVIDER_FILE)) return JSON.parse(readFileSync(PROVIDER_FILE, 'utf8')) } catch {} return { default: 'bedrock', ollama: { url: 'http://localhost:11434', model: 'qwen2.5:32b' }, perAgent: {} } }
function saveProvider(d) { writeFileSync(PROVIDER_FILE, JSON.stringify(d, null, 2)) }

function getProviderForAgent(agentId) {
  const prov = loadProvider()
  return prov.perAgent?.[agentId] || prov.default || 'bedrock'
}

async function* streamOllama(systemPrompt, userText, signal, agentId) {
  const prov = loadProvider()
  const ollamaUrl = prov.ollama?.url || 'http://localhost:11434'
  const ollamaModel = prov.ollama?.model || 'qwen2.5:32b'
  console.log(`[Ollama] agent=${agentId} model=${ollamaModel}`)

  const resp = await fetch(`${ollamaUrl}/api/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: ollamaModel,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userText }
      ],
      stream: true
    }),
    signal
  })

  if (!resp.ok) throw new Error(`Ollama error: ${resp.status}`)
  let inputTokens = 0, outputTokens = 0
  const reader = resp.body.getReader()
  const decoder = new TextDecoder()
  let buffer = ''

  while (true) {
    const { done, value } = await reader.read()
    if (done) break
    if (signal?.aborted) break
    buffer += decoder.decode(value, { stream: true })
    const lines = buffer.split('\n')
    buffer = lines.pop() || ''
    for (const line of lines) {
      if (!line.trim()) continue
      try {
        const json = JSON.parse(line)
        if (json.message?.content) yield json.message.content
        if (json.eval_count) outputTokens = json.eval_count
        if (json.prompt_eval_count) inputTokens = json.prompt_eval_count
      } catch {}
    }
  }
  try { trackUsage(agentId || 'unknown', ollamaModel, inputTokens, outputTokens) } catch {}
}

// ── Unified Stream (Bedrock or Ollama) ──────────────────
async function* streamAI(systemPrompt, userText, signal, agentId) {
  const provider = getProviderForAgent(agentId)
  if (provider === 'ollama') {
    yield* streamOllama(systemPrompt, userText, signal, agentId)
  } else {
    yield* streamBedrock(systemPrompt, userText, signal, agentId)
  }
}

// ── Agent Tools: Web Search ─────────────────────────────
const TAVILY_KEY = process.env.TAVILY_API_KEY || (() => { try { return readFileSync(join(HOME, '.tavily_key'), 'utf8').trim() } catch { return '' } })()

async function webSearch(query, maxResults = 5) {
  if (!TAVILY_KEY) {
    // Fallback to ~/bin/search if available
    try {
      const result = execSync(`${HOME}/bin/search "${query.replace(/"/g, '\\"')}" 2>/dev/null`, { encoding: 'utf8', timeout: 15000 })
      return result.slice(0, 2000)
    } catch { return 'Search unavailable — no Tavily key or search CLI found.' }
  }
  try {
    const resp = await fetch('https://api.tavily.com/search', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ api_key: TAVILY_KEY, query, max_results: maxResults, include_answer: true })
    })
    const data = await resp.json()
    let text = data.answer ? `Answer: ${data.answer}\n\n` : ''
    for (const r of (data.results || []).slice(0, maxResults)) {
      text += `• ${r.title}\n  ${r.url}\n  ${r.content?.slice(0, 200) || ''}\n\n`
    }
    return text || 'No results found.'
  } catch (e) { return `Search error: ${e.message}` }
}

// ── Agent Tools: File Read ──────────────────────────────
function readLocalFile(filePath) {
  try {
    const safe = resolve(HOME, filePath)
    if (!safe.startsWith(HOME)) return 'Access denied — path outside home directory.'
    if (!existsSync(safe)) return `File not found: ${filePath}`
    const stat = statSync(safe)
    if (stat.isDirectory()) {
      const items = readdirSync(safe).slice(0, 50)
      return `Directory listing (${items.length} items):\n` + items.join('\n')
    }
    if (stat.size > 100000) return `File too large (${stat.size} bytes). Max 100KB.`
    return readFileSync(safe, 'utf8')
  } catch (e) { return `Error reading file: ${e.message}` }
}

// ── Provider API + Tools API registered below after Fastify init ──

// ── Fastify ─────────────────────────────────────────────
const app = Fastify({ logger: false, requestTimeout: 300000, keepAliveTimeout: 300000 })
await app.register(cors)
await app.register(websocket)
await app.register(multipart, { limits: { fileSize: 100 * 1024 * 1024 } }) // 100MB max
await app.register(fstatic, {
  root: join(__dirname, '..', 'frontend'),
  prefix: '/',
  cacheControl: false,
  setHeaders: (res) => {
    res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate')
    res.setHeader('Pragma', 'no-cache')
    res.setHeader('Expires', '0')
  }
})

// Root → dashboard redirect
app.get('/', async (req, reply) => {
  reply.redirect('/dashboard/')
})

// ── Auth System ─────────────────────────────────────────
const AUTH_FILE = join(__dirname, 'data', 'auth.json')
function loadAuth() { try { if (existsSync(AUTH_FILE)) return JSON.parse(readFileSync(AUTH_FILE, 'utf8')) } catch {} return { users: { richard: { password: 'magi2026', role: 'admin', name: 'Richard' } }, sessions: {} } }
function saveAuth(d) { writeFileSync(AUTH_FILE, JSON.stringify(d, null, 2)) }

app.post('/api/auth/login', async (req) => {
  const { username, password } = req.body || {}
  const auth = loadAuth()
  const user = auth.users[username]
  if (!user || user.password !== password) return { ok: false, error: 'Invalid credentials' }
  const token = crypto.randomBytes(32).toString('hex')
  auth.sessions[token] = { username, role: user.role, name: user.name, createdAt: Date.now() }
  saveAuth(auth)
  trackEvent('auth_login', { username })
  return { ok: true, token, user: { username, role: user.role, name: user.name } }
})

app.post('/api/auth/logout', async (req) => {
  const token = (req.headers.authorization || '').replace('Bearer ', '')
  if (token) { const auth = loadAuth(); delete auth.sessions[token]; saveAuth(auth) }
  return { ok: true }
})

app.get('/api/auth/me', async (req) => {
  const token = (req.headers.authorization || '').replace('Bearer ', '')
  const auth = loadAuth()
  const session = auth.sessions[token]
  if (!session) return { ok: false, error: 'Not authenticated' }
  return { ok: true, user: { username: session.username, role: session.role, name: session.name } }
})

// ── Registration (pending approval) ──
app.post('/api/auth/register', async (req) => {
  const { username, password } = req.body || {}
  if (!username || !password) return { ok: false, error: 'Username and password required' }
  if (username.length < 3 || username.length > 20) return { ok: false, error: 'Username must be 3-20 characters' }
  if (!/^[a-zA-Z0-9_]+$/.test(username)) return { ok: false, error: 'Username: letters, numbers, underscore only' }
  if (password.length < 6) return { ok: false, error: 'Password must be at least 6 characters' }
  const auth = loadAuth()
  if (auth.users[username]) return { ok: false, error: 'Username already taken' }
  if (!auth.pending) auth.pending = {}
  if (auth.pending[username]) return { ok: false, error: 'Registration already pending approval' }
  auth.pending[username] = { password, requestedAt: Date.now(), status: 'pending' }
  saveAuth(auth)
  trackEvent('auth_register_request', { username })
  addNotification('New registration', username + ' requested access', 'info', 'auth')
  return { ok: true, message: 'Registration submitted — awaiting admin approval' }
})

// ── User Management (admin only) ──
function requireAdmin(req) {
  const token = (req.headers.authorization || '').replace('Bearer ', '')
  const auth = loadAuth()
  const session = auth.sessions[token]
  if (!session || session.role !== 'admin') return null
  return session
}

function requireAuth(req) {
  const token = (req.headers.authorization || '').replace('Bearer ', '')
  const auth = loadAuth()
  const session = auth.sessions[token]
  if (!session) return null
  return session
}

app.get('/api/admin/users', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const auth = loadAuth()
  const users = Object.entries(auth.users).map(([username, u]) => ({
    username, role: u.role, name: u.name || username
  }))
  const pending = Object.entries(auth.pending || {}).map(([username, p]) => ({
    username, requestedAt: p.requestedAt, status: p.status
  }))
  return { ok: true, users, pending }
})

app.post('/api/admin/users/approve', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username, role } = req.body || {}
  if (!username) return { ok: false, error: 'Username required' }
  const auth = loadAuth()
  if (!auth.pending || !auth.pending[username]) return { ok: false, error: 'No pending registration for this user' }
  const p = auth.pending[username]
  auth.users[username] = { password: p.password, role: role || 'user', name: username }
  delete auth.pending[username]
  saveAuth(auth)
  trackEvent('auth_user_approved', { username, role: role || 'viewer' })
  return { ok: true }
})

app.post('/api/admin/users/reject', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username } = req.body || {}
  if (!username) return { ok: false, error: 'Username required' }
  const auth = loadAuth()
  if (auth.pending && auth.pending[username]) { delete auth.pending[username]; saveAuth(auth) }
  trackEvent('auth_user_rejected', { username })
  return { ok: true }
})

app.put('/api/admin/users/:username/role', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username } = req.params
  const { role } = req.body || {}
  if (!role || !['admin', 'user'].includes(role)) return { ok: false, error: 'Role must be admin or user' }
  const auth = loadAuth()
  if (!auth.users[username]) return { ok: false, error: 'User not found' }
  auth.users[username].role = role
  saveAuth(auth)
  trackEvent('auth_role_change', { username, role })
  return { ok: true }
})

app.delete('/api/admin/users/:username', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username } = req.params
  const auth = loadAuth()
  if (!auth.users[username]) return { ok: false, error: 'User not found' }
  if (username === 'lucy') return { ok: false, error: 'Cannot delete core admin account' }
  delete auth.users[username]
  // Remove their sessions too
  for (const [token, s] of Object.entries(auth.sessions || {})) {
    if (s.username === username) delete auth.sessions[token]
  }
  saveAuth(auth)
  trackEvent('auth_user_deleted', { username })
