const DIAGRAMS_DIR = join(__dirname, '..', 'frontend', 'diagrams')
if (!existsSync(DIAGRAMS_DIR)) mkdirSync(DIAGRAMS_DIR, { recursive: true })

const VISUAL_SOUL = `You are a visual explainer. Generate a COMPLETE, self-contained HTML page.
Requirements:
- Single HTML file with ALL CSS and JS inline
- Use Mermaid.js (CDN: https://cdn.jsdelivr.net/npm/mermaid@11/dist/mermaid.min.js) for flowcharts/diagrams
- Use Chart.js (CDN: https://cdn.jsdelivr.net/npm/chart.js) for data charts if needed
- Dark theme default: background #1a1a2e, text #e0e0e0, accent #3B7DD8
- Clean typography: system-ui font stack, generous whitespace
- Responsive: works on mobile and desktop
- Add a subtle header with the title
- NO external dependencies besides CDN links above
- Return ONLY the HTML. No markdown, no explanation, no code fences.`

async function generateVisual(topic, agentContext) {
  const prompt = agentContext
    ? `Based on this agent discussion:\n\n${agentContext}\n\nGenerate a visual HTML page explaining/diagramming: ${topic}`
    : `Generate a visual HTML page explaining/diagramming: ${topic}`

  let html = ''
  for await (const chunk of streamAI(VISUAL_SOUL, prompt)) {
    html += chunk
  }
  // Clean up any markdown fences
  html = html.replace(/^```html?\n?/i, '').replace(/\n?```$/i, '').trim()
  if (!html.startsWith('<!DOCTYPE') && !html.startsWith('<html')) {
    const idx = html.indexOf('<!DOCTYPE')
    if (idx === -1) {
      const idx2 = html.indexOf('<html')
      if (idx2 > -1) html = html.slice(idx2)
    } else {
      html = html.slice(idx)
    }
  }
  // Fix truncated HTML — ensure it has closing tags
  if (!html.includes('</body>')) {
    html += '\n</style>\n</head>\n<body>\n<main style="padding:40px;text-align:center;color:#e0e0e0;font-family:system-ui">\n<h2 style="color:#fbbf24">⚠️ Visual was too complex</h2>\n<p style="color:#8b95a8;margin-top:12px">The AI response was truncated. Try a simpler topic or shorter prompt.</p>\n</main>\n</body>\n</html>'
  } else if (!html.includes('</html>')) {
    html += '\n</html>'
  }
  return html
}

app.post('/api/visual', async (req) => {
  const { topic, context } = req.body || {}
  if (!topic) return { ok: false, error: 'Missing topic' }
  try {
    const html = await generateVisual(topic, context)
    const slug = topic.toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 60)
    const filename = slug + '-' + Date.now() + '.html'
    writeFileSync(join(DIAGRAMS_DIR, filename), html, 'utf8')
    return { ok: true, url: '/diagrams/' + filename, filename }
  } catch (err) {
    return { ok: false, error: err.message }
  }
})

