function resolvePath(p) {
  if (!p || p === '~') return HOME
  if (p.startsWith('~/')) return join(HOME, p.slice(2))
  return resolve('/', normalize(p))
}

// List directory
app.get('/api/files', async (req) => {
  const dirPath = resolvePath(req.query.path || HOME)
  try {
    const entries = readdirSync(dirPath, { withFileTypes: true })
    const items = entries.map(e => {
      const fullPath = join(dirPath, e.name)
      try {
        const st = statSync(fullPath)
        return {
          name: e.name,
          path: fullPath,
          isDir: e.isDirectory(),
          size: st.size,
          modified: st.mtime.toISOString(),
          permissions: '0' + (st.mode & 0o777).toString(8)
        }
      } catch {
        return { name: e.name, path: fullPath, isDir: e.isDirectory(), size: 0, modified: null, permissions: '---' }
      }
    }).sort((a, b) => {
      if (a.isDir !== b.isDir) return a.isDir ? -1 : 1
      return a.name.localeCompare(b.name)
    })
    return { path: dirPath, items, parent: dirPath === '/' ? null : dirname(dirPath) }
  } catch (err) {
    return { path: dirPath, items: [], error: err.message }
  }
})

// Read file content
app.get('/api/files/read', async (req, reply) => {
  const filePath = resolvePath(req.query.path || '')
  if (!existsSync(filePath)) return reply.code(404).send({ error: 'Not found' })
  const st = statSync(filePath)
  if (st.isDirectory()) return reply.code(400).send({ error: 'Is a directory' })
  if (st.size > 5 * 1024 * 1024) return reply.code(400).send({ error: 'File too large (>5MB). Use download instead.' })
  try {
    const content = readFileSync(filePath, 'utf8')
    return { path: filePath, content, size: st.size }
  } catch {
    return reply.code(400).send({ error: 'Cannot read as text (binary file?)' })
  }
})

// Download file
app.get('/api/files/download', async (req, reply) => {
  const filePath = resolvePath(req.query.path || '')
  if (!existsSync(filePath)) return reply.code(404).send({ error: 'Not found' })
  const st = statSync(filePath)
  if (st.isDirectory()) return reply.code(400).send({ error: 'Is a directory' })
  const filename = filePath.split('/').pop()
  reply.header('Content-Disposition', `attachment; filename="${filename}"`)
  reply.header('Content-Type', 'application/octet-stream')
  reply.header('Content-Length', st.size)
  return reply.send(createReadStream(filePath))
})

// Upload file
app.post('/api/files/upload', async (req) => {
  const parts = req.parts()
  let targetDir = HOME
  let savedFiles = []
  for await (const part of parts) {
    if (part.type === 'field' && part.fieldname === 'path') {
      targetDir = resolvePath(part.value)
    }
    if (part.type === 'file') {
      const dest = join(targetDir, part.filename)
      if (!existsSync(targetDir)) mkdirSync(targetDir, { recursive: true })
      await pipeline(part.file, createWriteStream(dest))
      savedFiles.push({ name: part.filename, path: dest, size: statSync(dest).size })
    }
  }
  return { ok: true, files: savedFiles }
})

