  if (q.status) filtered = filtered.filter(c => c.status === q.status)
  if (q.tag) filtered = filtered.filter(c => (c.tags||[]).includes(q.tag))
  if (q.minScore) filtered = filtered.filter(c => (c.score||0) >= parseInt(q.minScore))
  const page = parseInt(q.page) || 1, limit = Math.min(parseInt(q.limit) || 50, 200)
  const sorted = filtered.sort((a, b) => (b.score || 0) - (a.score || 0))
  return { total: filtered.length, page, pages: Math.ceil(filtered.length / limit), contacts: sorted.slice((page-1)*limit, page*limit) }
})

