app.post('/api/icat/contacts/import', async (req) => {
  const { filters } = req.body || {}
  const leads = loadLeads()
  let filtered = leads
  if (filters?.province) filtered = filtered.filter(l => l.provinsi === filters.province)
  if (filters?.city) filtered = filtered.filter(l => l.kota === filters.city)
  if (filters?.tier) { const tiers = filters.tier.split(','); filtered = filtered.filter(l => tiers.includes(l.tier)) }
  if (filters?.hasWA) filtered = filtered.filter(l => l.wa_number)
  if (filters?.minScore) filtered = filtered.filter(l => (l.score||0) >= parseInt(filters.minScore))
  const maxImport = Math.min(parseInt(filters?.limit) || 100, 500)
  filtered = filtered.slice(0, maxImport)

  const data = loadContacts()
  const existing = new Set(data.contacts.map(c => c.phone || c.waNumber))
  let imported = 0
  for (const l of filtered) {
    const phone = l.telepon || l.wa_number || ''
    if (!phone || existing.has(phone)) continue
    data.contacts.push({
      id: data.nextId++, name: l.nama||'', phone, waNumber: l.wa_number||phone,
      business: l.jenis||l.kategori||'', province: l.provinsi||'', city: l.kota||'',
