      notes: '', score: l.score||50, status: 'new', optedOut: false,
      createdAt: Date.now(), updatedAt: Date.now(), lastContact: null, messageCount: 0
    })
    existing.add(phone)
    imported++
  }
  saveContacts(data)
  trackEvent('icat_import', { count: imported, filters })
  return { ok: true, imported, total: data.contacts.length }
})

