const LEADS_FILE = '/home/openclaw/council-room/data/scored/combined_scored.json'
let leadsCache = null
let leadsStats = null

function loadLeads() {
  if (leadsCache) return leadsCache
  try {
    leadsCache = JSON.parse(readFileSync(LEADS_FILE, 'utf8'))
    console.log(`Loaded ${leadsCache.length} leads`)
  } catch (e) {
    console.error('Failed to load leads:', e.message)
    leadsCache = []
  }
  return leadsCache
}

function getLeadsStats() {
  if (leadsStats) return leadsStats
  const leads = loadLeads()
  const stats = {
    total: leads.length,
    hasWA: 0, hasPhone: 0, noContact: 0,
    tiers: {}, provinces: {}, categories: {}, cities: {}, sources: {}
  }
  for (const l of leads) {
    if (l.wa_number) stats.hasWA++
    if (l.telepon) stats.hasPhone++
    if (!l.wa_number && !l.telepon) stats.noContact++
    stats.tiers[l.tier || '?'] = (stats.tiers[l.tier || '?'] || 0) + 1
    stats.provinces[l.provinsi || '?'] = (stats.provinces[l.provinsi || '?'] || 0) + 1
    const cat = l.kategori || l.jenis || '?'
    stats.categories[cat] = (stats.categories[cat] || 0) + 1
    if (l.kota) stats.cities[l.kota] = (stats.cities[l.kota] || 0) + 1
    const src = l.source || l.sumber || '?'
    stats.sources[src] = (stats.sources[src] || 0) + 1
  }
  leadsStats = stats
  return stats
}

app.get('/api/leads/stats', async () => getLeadsStats())

app.get('/api/leads', async (req) => {
  const leads = loadLeads()
  const q = req.query
  const page = parseInt(q.page) || 1
  const limit = Math.min(parseInt(q.limit) || 50, 500)
  const offset = (page - 1) * limit

  let filtered = leads

  // Filters
  if (q.province) filtered = filtered.filter(l => l.provinsi === q.province)
  if (q.city) filtered = filtered.filter(l => l.kota === q.city)
  if (q.tier) {
    const tiers = q.tier.split(',')
    filtered = filtered.filter(l => tiers.includes(l.tier))
  }
  if (q.category) filtered = filtered.filter(l => (l.kategori || l.jenis) === q.category)
  if (q.hasWA === 'true') filtered = filtered.filter(l => l.wa_number)
  if (q.hasPhone === 'true') filtered = filtered.filter(l => l.telepon)
  if (q.minScore) filtered = filtered.filter(l => (l.score || 0) >= parseInt(q.minScore))
  if (q.maxScore) filtered = filtered.filter(l => (l.score || 0) <= parseInt(q.maxScore))
  if (q.search) {
    const s = q.search.toLowerCase()
    filtered = filtered.filter(l =>
      (l.nama || '').toLowerCase().includes(s) ||
      (l.alamat || '').toLowerCase().includes(s) ||
      (l.jenis || '').toLowerCase().includes(s) ||
      (l.telepon || '').includes(s)
    )
  }

  // Sort
  const sortBy = q.sortBy || 'score'
  const sortDir = q.sortDir === 'asc' ? 1 : -1
  filtered.sort((a, b) => {
    const va = a[sortBy] ?? ''
    const vb = b[sortBy] ?? ''
    if (typeof va === 'number' && typeof vb === 'number') return (va - vb) * sortDir
    return String(va).localeCompare(String(vb)) * sortDir
  })

  return {
    total: filtered.length,
    page, limit,
    pages: Math.ceil(filtered.length / limit),
    data: filtered.slice(offset, offset + limit)
  }
})

