// ── WhatsApp Allowlist API ───────────────────────────────
const OPENCLAW_CONFIG = join(HOME, '.openclaw', 'openclaw.json')
const WA_CONTACTS_FILE = join(HOME, '.openclaw', 'wa-contacts.json')

function readOpenClawConfig() {
  return JSON5.parse(readFileSync(OPENCLAW_CONFIG, 'utf8'))
}

function writeOpenClawConfig(cfg) {
  writeFileSync(OPENCLAW_CONFIG, JSON.stringify(cfg, null, 2))
}

function readWAContacts() {
  try { if (existsSync(WA_CONTACTS_FILE)) return JSON.parse(readFileSync(WA_CONTACTS_FILE, 'utf8')) } catch {}
  return {}
}

function writeWAContacts(data) {
  writeFileSync(WA_CONTACTS_FILE, JSON.stringify(data, null, 2))
}

function formatNumber(number) {
  number = number.trim()
  if (number.startsWith('08')) number = '+62' + number.slice(1)
  else if (number.startsWith('62')) number = '+' + number
  else if (!number.startsWith('+')) number = '+' + number
  return number
}

function restartGateway() {
  execCb('openclaw gateway restart', (err, stdout, stderr) => {
    if (err) console.error('[gateway restart] error:', err.message)
    else console.log('[gateway restart] ok')
  })
}

// GET — return allowFrom merged with metadata
app.get('/wa-allowlist', async () => {
  try {
    const cfg = readOpenClawConfig()
    const allowFrom = cfg?.channels?.whatsapp?.allowFrom || []
    const meta = readWAContacts()
    const contacts = allowFrom.map(number => ({
      number,
      label: meta[number]?.label || '',
      role: meta[number]?.role || 'friend',
      access: meta[number]?.access || 'basic'
    }))
    return { ok: true, contacts }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

// POST — add new contact to both openclaw.json allowFrom AND wa-contacts.json
app.post('/wa-allowlist', async (req) => {
  try {
    let { number, label, role, access } = req.body || {}
    if (!number || typeof number !== 'string') return { ok: false, error: 'number required' }
    number = formatNumber(number)
    const cfg = readOpenClawConfig()
    if (!cfg.channels) cfg.channels = {}
    if (!cfg.channels.whatsapp) cfg.channels.whatsapp = {}
    if (!Array.isArray(cfg.channels.whatsapp.allowFrom)) cfg.channels.whatsapp.allowFrom = []
    if (cfg.channels.whatsapp.allowFrom.includes(number)) {
      return { ok: false, error: 'Number already in allowlist' }
    }
    cfg.channels.whatsapp.allowFrom.push(number)
    writeOpenClawConfig(cfg)
    // Save metadata
    const meta = readWAContacts()
    meta[number] = { label: label || '', role: role || 'friend', access: access || 'basic' }
    writeWAContacts(meta)
    restartGateway()
    trackEvent('wa_allowlist_add', { number, label, role, access })
    // Return merged contacts
    const contacts = cfg.channels.whatsapp.allowFrom.map(n => ({
      number: n, label: meta[n]?.label || '', role: meta[n]?.role || 'friend', access: meta[n]?.access || 'basic'
    }))
    return { ok: true, contacts }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

// PUT — update metadata only (label/role/access) without touching openclaw.json
app.put('/wa-allowlist', async (req) => {
  try {
    const { number, label, role, access } = req.body || {}
    if (!number) return { ok: false, error: 'number required' }
    const meta = readWAContacts()
    if (!meta[number]) meta[number] = {}
    if (label !== undefined) meta[number].label = label
    if (role !== undefined) meta[number].role = role
    if (access !== undefined) meta[number].access = access
    writeWAContacts(meta)
    trackEvent('wa_allowlist_update', { number, label, role, access })
    return { ok: true, contact: { number, ...meta[number] } }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

// DELETE — remove from both files
app.delete('/wa-allowlist', async (req) => {
  try {
    const { number } = req.body || {}
    if (!number) return { ok: false, error: 'number required' }
    const cfg = readOpenClawConfig()
    const list = cfg?.channels?.whatsapp?.allowFrom || []
    const idx = list.indexOf(number)
    if (idx === -1) return { ok: false, error: 'Number not found in allowlist' }
    list.splice(idx, 1)
    writeOpenClawConfig(cfg)
    // Remove from metadata
    const meta = readWAContacts()
    delete meta[number]
    writeWAContacts(meta)
    restartGateway()
    trackEvent('wa_allowlist_remove', { number })
    // Return merged contacts
    const contacts = list.map(n => ({
      number: n, label: meta[n]?.label || '', role: meta[n]?.role || 'friend', access: meta[n]?.access || 'basic'
    }))
    return { ok: true, contacts }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

