// POST — add a new rule
app.post('/wa-forward-rules', async (req) => {
  try {
    const { from, action, to, label } = req.body || {}
    if (!from || !action || !to) return { ok: false, error: 'from, action, and to are required' }
    if (!['forward', 'forward_summarize', 'notify'].includes(action)) return { ok: false, error: 'Invalid action. Must be forward, forward_summarize, or notify' }
    const rules = loadForwardRules()
    const newRule = { from: formatNumber(from), action, to: formatNumber(to), label: label || '' }
    rules.push(newRule)
    saveForwardRules(rules)
    trackEvent('wa_forward_rule_add', { from: newRule.from, action, to: newRule.to, label: newRule.label })
    // Return enriched list
    const meta = readWAContacts()
    const enriched = rules.map((r, i) => ({
      ...r, index: i,
      fromLabel: meta[r.from]?.label || r.from,
      toLabel: meta[r.to]?.label || r.to
    }))
    return { ok: true, rules: enriched }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

// PUT — update a rule by index
app.put('/wa-forward-rules', async (req) => {
