// ── Knowledge Base ──────────────────────────────────────
const KB_DIR = join(HOME, '.openclaw/workspace/knowledge-base')
const KB_INDEX = join(KB_DIR, 'index.json')

function loadKBIndex() {
  try {
    if (!existsSync(KB_DIR)) mkdirSync(KB_DIR, { recursive: true })
    if (!existsSync(KB_INDEX)) writeFileSync(KB_INDEX, JSON.stringify({ version: 1, entries: [] }, null, 2))
    return JSON.parse(readFileSync(KB_INDEX, 'utf8'))
  } catch (e) { return { version: 1, entries: [] } }
}

function saveKBIndex(data) {
  if (!existsSync(KB_DIR)) mkdirSync(KB_DIR, { recursive: true })
  writeFileSync(KB_INDEX, JSON.stringify(data, null, 2))
}

function slugify(text) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 80)
}

// GET /api/knowledge-base — list all entries
app.get('/api/knowledge-base', async (req) => {
  const data = loadKBIndex()
  const q = (req.query.q || '').toLowerCase()
  const cat = (req.query.category || '').toLowerCase()
  const tag = (req.query.tag || '').toLowerCase()
  let entries = data.entries || []
  if (q) entries = entries.filter(e =>
    e.title.toLowerCase().includes(q) ||
    (e.summary || '').toLowerCase().includes(q) ||
    (e.tags || []).some(t => t.toLowerCase().includes(q))
  )
  if (cat) entries = entries.filter(e => (e.category || '').toLowerCase() === cat)
  if (tag) entries = entries.filter(e => (e.tags || []).some(t => t.toLowerCase() === tag))
  entries.sort((a, b) => new Date(b.created) - new Date(a.created))
  return { ok: true, entries, total: entries.length }
})

// GET /api/knowledge-base/:id — get full content
app.get('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const entry = (data.entries || []).find(e => e.id === req.params.id)
  if (!entry) return { ok: false, error: 'Entry not found' }
  let content = ''
  try {
    const fp = join(KB_DIR, entry.content_file)
    const norm = normalize(fp)
    if (!norm.startsWith(KB_DIR)) return { ok: false, error: 'Invalid path' }
    content = readFileSync(norm, 'utf8')
  } catch (e) { content = '(Content file not found)' }
  return { ok: true, entry: { ...entry, content } }
})

// POST /api/knowledge-base — save new entry
app.post('/api/knowledge-base', async (req) => {
  const { title, category, tags, content, summary, source } = req.body || {}
  if (!title || !content) return { ok: false, error: 'title and content required' }
  const data = loadKBIndex()
  const id = crypto.randomUUID()
  const slug = slugify(title)
  let filename = slug + '.md'
  if (existsSync(join(KB_DIR, filename))) {
    let c = 2
    while (existsSync(join(KB_DIR, slug + '-' + c + '.md'))) c++
    filename = slug + '-' + c + '.md'
  }
  const now = new Date().toISOString()
  const words = content.split(/\s+/).filter(Boolean).length
  const entry = {
    id,
    title,
    category: category || 'research',
    tags: Array.isArray(tags) ? tags : (tags || 'general').split(',').map(t => t.trim()).filter(Boolean),
    summary: summary || content.replace(/#/g, '').replace(/\n/g, ' ').trim().substring(0, 200),
    content_file: filename,
    created: now,
    updated: now,
    source: source || 'magi-web',
    word_count: words
  }
  writeFileSync(join(KB_DIR, filename), content)
  data.entries.push(entry)
  saveKBIndex(data)
  return { ok: true, entry }
})

// PUT /api/knowledge-base/:id — update entry
app.put('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const idx = (data.entries || []).findIndex(e => e.id === req.params.id)
  if (idx < 0) return { ok: false, error: 'Entry not found' }
  const { title, category, tags, content, summary } = req.body || {}
  const entry = data.entries[idx]
  if (title) entry.title = title
  if (category) entry.category = category
  if (tags) entry.tags = Array.isArray(tags) ? tags : tags.split(',').map(t => t.trim()).filter(Boolean)
  if (summary) entry.summary = summary
  entry.updated = new Date().toISOString()
  if (content) {
    writeFileSync(join(KB_DIR, entry.content_file), content)
    entry.word_count = content.split(/\s+/).filter(Boolean).length
  }
  data.entries[idx] = entry
  saveKBIndex(data)
  return { ok: true, entry }
})

// DELETE /api/knowledge-base/:id — delete entry
app.delete('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const idx = (data.entries || []).findIndex(e => e.id === req.params.id)
  if (idx < 0) return { ok: false, error: 'Entry not found' }
  const entry = data.entries[idx]
  try {
    const fp = join(KB_DIR, entry.content_file)
    if (existsSync(fp)) unlinkSync(fp)
  } catch {}
  data.entries.splice(idx, 1)
  saveKBIndex(data)
  return { ok: true }
})

