// Non-streaming Bedrock helper — collects full response as string
async function callBedrockSimple(prompt, agentId) {
  let result = ''
  for await (const chunk of streamAI(
    FORMAT_PROMPT,
    prompt,
    null,
    agentId || 'sarael'
  )) {
    result += chunk
  }
  return result
}

const DEEP_THINKS_FILE = join(__dirname, 'data', 'deep-thinks.json')

app.post('/api/deep-think', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { topic, agents, rounds: requestedRounds } = req.body || {}
  if (!topic) return { ok: false, error: 'Topic required' }

  const debateAgents = agents || ['rafael', 'uriel', 'samael']
  const rounds = Math.min(Math.max(parseInt(requestedRounds) || 3, 1), 7)
  const DEEP_INTENSITY = INTENSITY_MODIFIERS[10] // Always max depth for Deep Think

  // Phase 1: Each agent gives initial take (parallel)
  const initialResponses = await Promise.all(debateAgents.map(async (agentId) => {
    const soul = AGENTS[agentId]?.soul || ''
    const prompt = `${soul}\n\n${getSharedContext()}\n\n${DEEP_INTENSITY}\n\nYou are in a DEEP THINK debate session. Topic: "${topic}"\n\nGive your FULL initial analysis and position. Be specific, opinionated, and constructive. Cover every angle: risks, opportunities, practical implementation, edge cases, trade-offs, and concrete recommendations. Do NOT hold back — this is maximum depth analysis.`
    const response = await callBedrockSimple(prompt, agentId)
    return { agentId, phase: 'initial', response }
  }))

  // Phase 2+: Multiple debate rounds
  const allDebateRounds = []
  let previousRound = initialResponses
  const debateRounds = Math.max(rounds - 2, 1) // rounds minus initial and synthesis

  for (let round = 1; round <= debateRounds; round++) {
    const roundLabel = debateRounds === 1 ? 'debate' : `debate-r${round}`
    const roundPrompts = {
      1: 'Respond to their points with FULL depth. Where do you agree? Where do you push back HARD? What critical things did they miss?',
      2: 'This is the COUNTER-DEBATE round. Challenge the strongest arguments from the previous round. Find weaknesses, propose alternatives, stress-test assumptions.',
      3: 'FINAL POSITIONS round. After hearing all arguments, state your refined position. What changed? What are you MORE convinced of? What compromise would you propose?',
      4: 'DEEP DIVE round. Pick the single most contentious or important point and analyze it exhaustively. Edge cases, failure modes, second-order effects.',

      5: 'CONVERGENCE round. Find the path forward that incorporates the best of all positions. Be specific about trade-offs you are accepting.'
    }
    const roundInstruction = roundPrompts[round] || roundPrompts[1]

    const roundResponses = await Promise.all(debateAgents.map(async (agentId) => {
      const soul = AGENTS[agentId]?.soul || ''
      const othersViews = previousRound.filter(r => r.agentId !== agentId)
        .map(r => `**${AGENTS[r.agentId]?.name || r.agentId}** said: ${r.response}`).join('\n\n')
      const prompt = `${soul}\n\n${getSharedContext()}\n\n${DEEP_INTENSITY}\n\nDEEP THINK debate continues (Round ${round + 1}/${rounds}). Topic: "${topic}"\n\nPrevious round:\n${othersViews}\n\n${roundInstruction} Be direct, thorough, and leave nothing unsaid.`
      const response = await callBedrockSimple(prompt, agentId)
      return { agentId, phase: roundLabel, response }
    }))

    allDebateRounds.push(...roundResponses)
    previousRound = roundResponses
  }

  // Final Phase: Synthesis
  const allContent = [...initialResponses, ...allDebateRounds]
    .map(r => `**${AGENTS[r.agentId]?.name || r.agentId}** (${r.phase}): ${r.response}`).join('\n\n---\n\n')
  const synthesisPrompt = `${DEEP_INTENSITY}\n\nYou are synthesizing a DEEP THINK debate session (${rounds} rounds, ${debateAgents.length} agents).\n\nTopic: "${topic}"\n\nAll agent contributions:\n${allContent}\n\nProduce a COMPREHENSIVE final synthesis:\n1. **Consensus Points** — what everyone agrees on\n2. **Key Debates** — where agents disagreed and the best resolution\n3. **Recommended Plan** — concrete action items with priorities (P0/P1/P2)\n4. **Risks & Mitigations** — top 5 risks identified with specific mitigations\n5. **Technical Architecture** — system design, tech stack, data flow\n6. **Open Questions** — what still needs to be decided\n7. **Timeline & Milestones** — phased delivery plan\n\nBe exhaustive, specific, and actionable. Include diagrams in text/ASCII where helpful. This is the definitive output of the session.`
  const synthesis = await callBedrockSimple(synthesisPrompt, 'sarael')

  const result = {
    id: 'dt-' + Date.now(),
    topic,
    agents: debateAgents,
    rounds,
    phases: { initial: initialResponses, debate: allDebateRounds },
    synthesis,
    createdAt: Date.now()
  }

  // Store
  let data = { items: [] }
  try { data = JSON.parse(readFileSync(DEEP_THINKS_FILE, 'utf8')) } catch {}
  data.items.unshift(result)
  if (data.items.length > 20) data.items = data.items.slice(0, 20)
  writeFileSync(DEEP_THINKS_FILE, JSON.stringify(data, null, 2))

  trackEvent('deep_think', { id: result.id, topic: topic.slice(0, 80), agents: debateAgents })
  addNotification('Deep Think completed', topic.slice(0, 60), 'info', 'deep-think')
  return { ok: true, result }
})

