  const byUser = {}
  for (const [date, users] of Object.entries(costs)) {
    for (const [user, data] of Object.entries(users)) {
      totals.input += data.input
      totals.output += data.output
      totals.calls += data.calls
      if (!byUser[user]) byUser[user] = { input: 0, output: 0, calls: 0 }
      byUser[user].input += data.input
      byUser[user].output += data.output
      byUser[user].calls += data.calls
    }
  }
  return { ok: true, daily: costs, totals, byUser }
})

